<template>
    <div class='diary'>
        <h1>diary</h1>
        <p class='p-text scorll-bar' v-html='plan'></p>
        <div class='content'>
            <table v-for='(cItem, cIndex) in calendar' :key ='cIndex'>
                <tr>
                    <td colspan='6'>{{cItem.date}}</td>
                </tr>
                <tr v-for='(lItem, lIndex) in cItem.list' :key='lIndex'>
                    <td 
                        @click='show(dItem)'
                        v-for='(dItem, dIndex) in lItem.day' 
                        :key='dIndex' 
                        :class="{'active': dItem.show, 'warning': dItem.warning}" 
                        :title='dItem.text'>
                        {{dItem.num}}
                    </td>
                </tr>
                <tr>
                    <td>31</td>
                </tr>
            </table>
        </div>
    </div>
</template>

<script>
    import {calendar} from '../js/sex.js'
    export default {
        data() {
            return {
                calendar,
                plan: ''
            };
        },
        methods:{
            show(v) {
                // console.log(v, 'vvv')
                this.plan = v.plan;
            },
            del() {
                this.plan = '';
            }
        },
        mounted() {
    
        }
    }
</script>



